parameters.jsCode:
const userId = $json.userId || 'anonymous_user';
const scenarioId = $json.scenarioId || 'commercial_negotiation';
const totalQuestions = Number($json.totalQuestions || 10);

const roleplaySessionId = `rp_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
const memoryKey = `${userId}:${roleplaySessionId}`;
const startedAt = new Date().toISOString();

return [
  {
    json: {
      ...$json,
      roleplaySessionId,
      memoryKey,
      startedAt,
      status: 'active',
      currentQuestionIndex: 1,
      totalQuestions,
      scenarioId,
      userId
    }
  }
];

let output = $json.output || $json.text || $json.message?.content || '';

// Remove markdown fences if the model adds them
if (typeof output === 'string') {
  output = output.replace(/```json/gi, '').replace(/```/g, '').trim();
}

let questions;

try {
  questions = typeof output === 'string' ? JSON.parse(output) : output;
} catch (e) {
  const match = output.match(/\[[\s\S]*\]/);
  if (match) {
    questions = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse questions JSON from AI output: ' + output.substring(0, 300));
  }
}

// Some models return { questions: [...] } instead of [...]
if (!Array.isArray(questions)) {
  questions = questions.questions || questions.turns || questions.items || questions.data;
}

if (!Array.isArray(questions) || questions.length === 0) {
  throw new Error('Parsed result is not a valid questions array');
}

// Safer: get session data from the Code node, not from the Postgres insert output
const sessionData = $('Code in JavaScript').first().json;
const roleplaySessionId = sessionData.roleplaySessionId || sessionData.id;
const totalQuestions = Number(sessionData.totalQuestions || 10);

if (questions.length < totalQuestions) {
  throw new Error(`Start Planner generated only ${questions.length} questions, expected ${totalQuestions}. Re-run Start Planner or make its prompt stricter.`);
}

function pick(obj, keys, fallback = '') {
  for (const key of keys) {
    if (obj && obj[key] !== undefined && obj[key] !== null && String(obj[key]).trim() !== '') {
      return obj[key];
    }
  }
  return fallback;
}

const selectedQuestions = questions.slice(0, totalQuestions);

const items = selectedQuestions.map((q, i) => {
  const questionIndex = Number(q.question_index || q.index || q.turn || i + 1);

  const questionText =
    typeof q === 'string'
      ? q
      : pick(q, [
          'question_text',
          'question',
          'client_message',
          'client_turn',
          'dialogue_line',
          'message',
          'text',
          'prompt'
        ]);

  if (!questionText) {
    throw new Error(
      `Question ${i + 1} is missing question_text. Available keys: ${Object.keys(q || {}).join(', ')}`
    );
  }

  const expectedFocus =
    typeof q === 'string'
      ? ''
      : pick(q, [
          'expected_focus',
          'expectedFocus',
          'focus',
          'ideal_response',
          'idealResponse',
          'learning_goal'
        ]);

  const scoringRubric =
    typeof q === 'string'
      ? ''
      : pick(q, [
          'scoring_rubric',
          'scoringRubric',
          'rubric',
          'criteria',
          'evaluation_criteria'
        ]);

  return {
    json: {
      roleplay_session_id: roleplaySessionId,
      question_index: questionIndex,
      question_text: questionText,
      expected_focus: expectedFocus,
      scoring_rubric: scoringRubric,
      status: 'pending',
      is_off_topic: false,
      redirect_used: false,
      answer_attempts: 0,
      meta: JSON.stringify({}),

      _is_first: questionIndex === 1,
      _first_question_text: selectedQuestions[0].question_text || selectedQuestions[0].question || selectedQuestions[0].client_message || selectedQuestions[0].message || selectedQuestions[0].text,
      _roleplay_session_id: roleplaySessionId
    }
  };
});

return items;

// 拿到所有插入的 items
const allItems = $input.all();

// 找第一题
const firstItem = allItems[0].json;

return [
  {
    json: {
      success: true,
      roleplaySessionId: firstItem._roleplay_session_id || firstItem.roleplay_session_id,
      currentQuestionIndex: 1,
      totalQuestions: 10,
      question: firstItem._first_question_text || firstItem.question_text,
      _userId: firstItem._userId || 'unknown'
    }
  }
];

const session = $json;

if (!session || !session.id) {
  throw new Error('No active session found for this user');
}

// 从 Edit Fields 拿原始请求数据
const input = $('Edit Fields').first().json;

return [
  {
    json: {
      sessionId: session.id,
      userId: session.user_id,
      scenarioId: session.scenario_id,
      currentQuestionIndex: session.current_question_index,
      totalQuestions: session.total_questions,
      memoryKey: session.memory_key,
      offTopicCount: session.off_topic_count,
      userMessage: input.message
    }
  }
];

