parameters.jsCode:
const question = $json;
const context = $('Get Current Question Index').first().json;
const input = $('Edit Fields').first().json;

return [
  {
    json: {
      sessionId: context.sessionId,
      roleplaySessionId: context.sessionId,
      userId: context.userId,
      scenarioId: context.scenarioId,
      currentQuestionIndex: context.currentQuestionIndex,
      totalQuestions: context.totalQuestions,
      memoryKey: context.memoryKey,
      offTopicCount: context.offTopicCount,
      userMessage: input.message,
      language: input.language || 'pt',
      questionText: question.question_text,
      expectedFocus: question.expected_focus,
      scoringRubric: question.scoring_rubric,
      questionId: question.id
    }
  }
];

let output = $json.output || $json.text || '';

output = output.replace(/```json/gi, '').replace(/```/g, '').trim();

let evaluation;
try {
  evaluation = JSON.parse(output);
} catch (e) {
  const match = output.match(/\{[\s\S]*\}/);
  if (match) {
    evaluation = JSON.parse(match[0]);
  } else {
    throw new Error('Failed to parse evaluation JSON: ' + output.substring(0, 200));
  }
}

const context = $('Prepare Evaluator Input').first().json;

return [
  {
    json: {
      ...evaluation,
      sessionId: context.sessionId,
      userId: context.userId,
      currentQuestionIndex: context.currentQuestionIndex,
      totalQuestions: context.totalQuestions,
      offTopicCount: context.offTopicCount,
      userMessage: context.userMessage,
      questionId: context.questionId,
      memoryKey: context.memoryKey,
      roleplaySessionId: context.roleplaySessionId,
      language: context.language || 'pt',
      isLastQuestion: context.currentQuestionIndex >= context.totalQuestions
    }
  }
];

const eval_data = $('Parse Evaluation').first().json;

// ─── 1. Off-topic: don't advance, redirect user ───
if (!eval_data.shouldAdvance) {
  return [{
    json: {
      success: true,
      type: 'redirect',
      roleplaySessionId: eval_data.sessionId,
      currentQuestionIndex: eval_data.currentQuestionIndex,
      totalQuestions: eval_data.totalQuestions,
      isOffTopic: true,
      isLastQuestion: eval_data.isLastQuestion,
      redirectMessage: eval_data.redirectMessage,
      question: eval_data.redirectMessage,
      score: null,
      feedback: '',
      positiveFeedback: '',
      completed: false
    }
  }];
}

// ─── 2. Last question + advance: return QUALITATIVE final feedback only ───
// IMPORTANT: no finalScore / overall numeric score is exposed to the learner.
if (eval_data.isLastQuestion) {
  let fb = null;
  try {
    fb = $('Parse Feedback').first().json.finalFeedback;
  } catch (e) {
    fb = null;
  }
  fb = fb || {};

  const strengths    = fb.what_went_well   || fb.strengths    || [];
  const improvements = fb.areas_to_improve || fb.improvements  || [];
  const nextSteps    = fb.next_steps       || fb.nextSteps     || [];
  const summary      = fb.summary || fb.finalFeedback ||
    'Sessão concluída. Reveja os pontos fortes e as áreas a melhorar abaixo.';

  return [{
    json: {
      success: true,
      type: 'completed',
      roleplaySessionId: eval_data.sessionId,
      currentQuestionIndex: eval_data.currentQuestionIndex,
      totalQuestions: eval_data.totalQuestions,
      isOffTopic: false,
      isLastQuestion: true,
      completed: true,

      // qualitative summary only — NO finalScore / final numeric grade
      finalFeedback: summary,
      strengths: strengths,
      improvements: improvements,
      nextSteps: nextSteps
    }
  }];
}

// ─── 3. Normal advance to next question ───
return [{
  json: {
    success: true,
    type: 'next_question',
    roleplaySessionId: eval_data.sessionId,
    currentQuestionIndex: eval_data.currentQuestionIndex + 1,
    totalQuestions: eval_data.totalQuestions,
    isOffTopic: false,
    isLastQuestion: false,
    question: eval_data.assistantMessage,

    // per-turn formative feedback
    score: eval_data.score ?? null,
    feedback: eval_data.feedback || '',
    positiveFeedback: eval_data.positiveFeedback || '',

    completed: false,
    _newQuestionIndex: eval_data.currentQuestionIndex + 1
  }
}];

const data = $json;

return [
  {
    json: {
      roleplay_session_id: data.sessionId,
      user_id: data.userId,
      question_index: data.currentQuestionIndex,
      sender: 'user',
      message_type: 'answer',
      content: data.userMessage,
      meta: JSON.stringify({}),
    }
  },
  {
    json: {
      roleplay_session_id: data.sessionId,
      user_id: data.userId,
      question_index: data.currentQuestionIndex,
      sender: 'assistant',
      message_type: 'feedback',
      content: data.feedback || data.positiveFeedback || data.redirectMessage || '',
      meta: JSON.stringify({ score: data.score ?? null, isOnTopic: data.isOnTopic }),
    }
  }
];

const messages = $input.all().map(i => i.json);
const transcript = messages
  .filter(m => m.sender === 'user' || m.sender === 'assistant')
  .map(m => `[${String(m.sender).toUpperCase()}] ${m.content}`)
  .join('\n\n');

const context = $('Parse Evaluation').first().json;

return [{
  json: {
    ...context,
    transcript,
    language: context.language || 'pt'
  }
}];

// Message a model (json_schema) returns a nested object, not a string.
let raw =
  $json.message?.content ??
  $json.output?.[0]?.content?.[0]?.text ??
  $json.content?.[0]?.text ??
  $json.output ??
  $json.text ??
  '';

let feedback;

if (raw && typeof raw === 'object') {
  // already parsed by the json_schema response format
  feedback = raw;
} else {
  let s = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
  try {
    feedback = JSON.parse(s);
  } catch (e) {
    const match = s.match(/\{[\s\S]*\}/);
    if (match) {
      feedback = JSON.parse(match[0]);
    } else {
      feedback = {
        summary: '',
        what_went_well: [],
        areas_to_improve: [],
        next_steps: ['Sessão concluída. Feedback indisponível devido a erro de processamento.'],
        _parse_error: true
      };
    }
  }
}

const context = $('Build Transcript').first().json;

return [{
  json: {
    ...context,
    finalFeedback: feedback
  }
}];

