textOptions.schema:
{
  "type": "object",
  "properties": {
    "summary": {
      "type": "string",
      "description": "1-2 sentence qualitative overall summary of the session, no numbers/grades."
    },
    "what_went_well": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "2 to 4 concrete points about what the trainee did well, each one short sentence."
    },
    "areas_to_improve": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "2 to 4 concrete and actionable points about where the trainee can improve."
    },
    "next_steps": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "2 to 4 specific suggestions for what to review or practice next."
    }
  },
  "required": [
    "summary",
    "what_went_well",
    "areas_to_improve",
    "next_steps"
  ],
  "additionalProperties": false
}
